	private <T> List<T> getByDate(String tableName, Date reportDate, Class<T> type) {
		String sql = "SELECT * FROM " + tableName + " WHERE REPORT_DATE = ?";
		return jdbcTemplate.query(sql, new BeanPropertyRowMapper<>(type), reportDate);
	}

	private <T> Optional<T> getOneByDate(String tableName, Date reportDate, Class<T> type) {
		List<T> rows = getByDate(tableName, reportDate, type);
		return rows.isEmpty() ? Optional.empty() : Optional.of(rows.get(0));
	}

	private <T> List<T> getByDateAndVersion(String tableName, Date reportDate, BigDecimal reportVersion, Class<T> type) {
		String sql = "SELECT * FROM " + tableName + " WHERE REPORT_DATE = ? AND REPORT_VERSION = ?";
		return jdbcTemplate.query(sql, new BeanPropertyRowMapper<>(type), reportDate, reportVersion);
	}

	private <T> Optional<T> getLatestByDate(String tableName, Date reportDate, Class<T> type) {
		String sql = "SELECT * FROM " + tableName
				+ " WHERE REPORT_DATE = ? AND REPORT_VERSION IS NOT NULL ORDER BY TO_NUMBER(REPORT_VERSION) DESC FETCH FIRST 1 ROWS ONLY";
		List<T> rows = jdbcTemplate.query(sql, new BeanPropertyRowMapper<>(type), reportDate);
		return rows.isEmpty() ? Optional.empty() : Optional.of(rows.get(0));
	}

	private <T> List<T> getAllWithVersion(String tableName, Class<T> type) {
		String sql = "SELECT * FROM " + tableName + " WHERE REPORT_VERSION IS NOT NULL ORDER BY REPORT_VERSION ASC";
		return jdbcTemplate.query(sql, new BeanPropertyRowMapper<>(type));
	}

	private BigDecimal findMaxVersion(String tableName, Date reportDate) {
		String sql = "SELECT MAX(REPORT_VERSION) FROM " + tableName + " WHERE REPORT_DATE = ?";
		return jdbcTemplate.queryForObject(sql, BigDecimal.class, reportDate);
	}

	private boolean existsByDateAndVersion(String tableName, Date reportDate, BigDecimal reportVersion) {
		String sql = "SELECT COUNT(*) FROM " + tableName + " WHERE REPORT_DATE = ? AND REPORT_VERSION = ?";
		Integer count = jdbcTemplate.queryForObject(sql, Integer.class, reportDate, reportVersion);
		return count != null && count > 0;
	}

	private void saveEntity(String tableName, Object entity, String... keyFields) {
		List<Field> fields = getPersistentFields(entity.getClass());
		List<Object> values = new ArrayList<>();
		List<String> columns = new ArrayList<>();

		for (Field field : fields) {
			field.setAccessible(true);
			columns.add(columnName(field.getName()));
			try {
				values.add(field.get(entity));
			} catch (IllegalAccessException e) {
				throw new IllegalStateException("Unable to read field " + field.getName(), e);
			}
		}

		String updateSql = buildUpdateSql(tableName, fields, keyFields);
		List<Object> updateArgs = buildUpdateArgs(entity, fields, keyFields);
		int updated = jdbcTemplate.update(updateSql, updateArgs.toArray());
		if (updated > 0) {
			return;
		}

		String placeholders = String.join(", ", Collections.nCopies(columns.size(), "?"));
		String insertSql = "INSERT INTO " + tableName + " (" + String.join(", ", columns) + ") VALUES (" + placeholders + ")";
		jdbcTemplate.update(insertSql, values.toArray());
	}

	private String buildUpdateSql(String tableName, List<Field> fields, String... keyFields) {
		List<String> keys = java.util.Arrays.asList(keyFields);
		List<String> setColumns = new ArrayList<>();
		List<String> whereColumns = new ArrayList<>();
		for (Field field : fields) {
			String column = columnName(field.getName());
			if (keys.contains(field.getName())) {
				whereColumns.add(column + " = ?");
			} else {
				setColumns.add(column + " = ?");
			}
		}
		return "UPDATE " + tableName + " SET " + String.join(", ", setColumns) + " WHERE " + String.join(" AND ", whereColumns);
	}

	private List<Object> buildUpdateArgs(Object entity, List<Field> fields, String... keyFields) {
		List<String> keys = java.util.Arrays.asList(keyFields);
		List<Object> args = new ArrayList<>();
		try {
			for (Field field : fields) {
				if (!keys.contains(field.getName())) {
					field.setAccessible(true);
					args.add(field.get(entity));
				}
			}
			for (Field field : fields) {
				if (keys.contains(field.getName())) {
					field.setAccessible(true);
					args.add(field.get(entity));
				}
			}
		} catch (IllegalAccessException e) {
			throw new IllegalStateException("Unable to build JDBC arguments", e);
		}
		return args;
	}

	private List<Field> getPersistentFields(Class<?> type) {
		List<Field> fields = new ArrayList<>();
		for (Field field : type.getDeclaredFields()) {
			if (!Modifier.isStatic(field.getModifiers())) {
				fields.add(field);
			}
		}
		return fields;
	}

	private String columnName(String fieldName) {
		return fieldName.replaceAll("([a-z])([A-Z])", "$1_$2").toUpperCase();
	}


	public ModelAndView getM_CA5View(String reportId, String fromdate, String todate, String currency, String dtltype,
			Pageable pageable, String type, BigDecimal version,HttpServletRequest req1,Model md) {

		ModelAndView mv = new ModelAndView();
		
		String userid = (String) req1.getSession().getAttribute("USERID");

		System.out.println("User Id Maker and Checker: " + userid);
		String role = userProfileRep.getUserRole(userid);
		md.addAttribute("role", role);
		System.out.println("Role: " + role);
		
		
		Session hs = sessionFactory.getCurrentSession();

		int pageSize = pageable.getPageSize();
		int currentPage = pageable.getPageNumber();
		int startItem = currentPage * pageSize;

		try {
			Date d1 = parseReportDate(todate);

			System.out.println("======= VIEW DEBUG =======");
			System.out.println("TYPE      : " + type);
			System.out.println("DTLTYPE   : " + dtltype);
			System.out.println("DATE      : " + d1);
			System.out.println("VERSION   : " + version);
			System.out.println("==========================");

			// ===========================================================
			// SUMMARY SECTION
			// ===========================================================

			// ---------- CASE 1: ARCHIVAL ----------
			if ("ARCHIVAL".equalsIgnoreCase(type) && version != null) {

				List<M_CA5_Archival_Summary_Entity1> T1Master = getByDateAndVersion(TBL_ARCH_SUMMARY1, d1, version, M_CA5_Archival_Summary_Entity1.class);
				List<M_CA5_Archival_Summary_Entity2> T2Master = getByDateAndVersion(TBL_ARCH_SUMMARY2, d1, version, M_CA5_Archival_Summary_Entity2.class);

				mv.addObject("reportsummary", T1Master);
				mv.addObject("reportsummary1", T2Master);
				mv.addObject("displaymode", "summary");

			}
			// ---------- CASE 2: RESUB ----------
			else if ("RESUB".equalsIgnoreCase(type) && version != null) {

				List<M_CA5_RESUB_Summary_Entity1> T1Master = getByDateAndVersion(TBL_RESUB_SUMMARY1, d1, version, M_CA5_RESUB_Summary_Entity1.class);
				List<M_CA5_RESUB_Summary_Entity2> T2Master = getByDateAndVersion(TBL_RESUB_SUMMARY2, d1, version, M_CA5_RESUB_Summary_Entity2.class);
				mv.addObject("reportsummary", T1Master);
				mv.addObject("reportsummary1", T2Master);
				mv.addObject("displaymode", "resubSummary");
			}

			// ---------- CASE 3: NORMAL ----------
			else {

				List<M_CA5_Summary_Entity1> T1Master = getByDate(TBL_SUMMARY1, d1, M_CA5_Summary_Entity1.class);
				List<M_CA5_Summary_Entity2> T2Master = getByDate(TBL_SUMMARY2, d1, M_CA5_Summary_Entity2.class);

				System.out.println("T1Master Size: " + T1Master.size());
				System.out.println("T2Master Size: " + T2Master.size());

				mv.addObject("reportsummary", T1Master);
				mv.addObject("reportsummary1", T2Master);
				mv.addObject("displaymode", "summary");
			}

			// ---------- CASE 4: DETAIL (NEW, ONLY ADDITION) ----------
			if ("detail".equalsIgnoreCase(dtltype)) {

				// DETAIL + ARCHIVAL
				if ("ARCHIVAL".equalsIgnoreCase(type) && version != null) {

					List<M_CA5_Archival_Detail_Entity1> T1Master = getByDateAndVersion(TBL_ARCH_DETAIL1, parseReportDate(todate), version, M_CA5_Archival_Detail_Entity1.class);
					List<M_CA5_Archival_Detail_Entity2> T2Master = getByDateAndVersion(TBL_ARCH_DETAIL2, parseReportDate(todate), version, M_CA5_Archival_Detail_Entity2.class);

					mv.addObject("displaymode", "Details");
					mv.addObject("reportsummary", T1Master);
					mv.addObject("reportsummary1", T2Master);
				}
				// ---------- RESUB DETAIL ----------
				else if ("RESUB".equalsIgnoreCase(type) && version != null) {

					List<M_CA5_RESUB_Detail_Entity1> T1Master = getByDateAndVersion(TBL_RESUB_DETAIL1, parseReportDate(todate), version, M_CA5_RESUB_Detail_Entity1.class);
					List<M_CA5_RESUB_Detail_Entity2> T2Master = getByDateAndVersion(TBL_RESUB_DETAIL2, parseReportDate(todate), version, M_CA5_RESUB_Detail_Entity2.class);

					System.out.println("Resub Detail Size : " + T1Master.size());

					mv.addObject("displaymode", "resubDetail");
					mv.addObject("reportsummary", T1Master);
					mv.addObject("reportsummary1", T2Master);

				}
				// DETAIL + NORMAL
				else {

					List<M_CA5_Detail_Entity1> T1Master = getByDate(TBL_DETAIL1, parseReportDate(todate), M_CA5_Detail_Entity1.class);
					List<M_CA5_Detail_Entity2> T2Master = getByDate(TBL_DETAIL2, parseReportDate(todate), M_CA5_Detail_Entity2.class);

					mv.addObject("displaymode", "Details");
					mv.addObject("reportsummary", T1Master);
					mv.addObject("reportsummary1", T2Master);
				}
			}

		} catch (ParseException e) {
			e.printStackTrace();
		}

		mv.setViewName("BRRS/M_CA5");

		System.out.println("View set to: " + mv.getViewName());

		return mv;
	}

	public void updateResubReport(M_CA5_RESUB_Summary_Entity1 updatedEntity1,
			M_CA5_RESUB_Summary_Entity2 updatedEntity2) {

		// ====================================================
		// 1️⃣ GET REPORT DATE
		// ====================================================

		Date reportDate1 = updatedEntity1.getReportDate();
		Date reportDate2 = updatedEntity2.getReportDate();

		if (reportDate1 == null || reportDate2 == null) {
			throw new RuntimeException("Report date cannot be null");
		}

		// ====================================================
		// 2️⃣ FETCH MAX VERSION FROM BOTH TABLES
		// ====================================================

		BigDecimal maxVer1 = findMaxVersion(TBL_RESUB_SUMMARY1, reportDate1);
		BigDecimal maxVer2 = findMaxVersion(TBL_RESUB_SUMMARY2, reportDate2);

		// If no previous version exists → start from 0
		if (maxVer1 == null)
			maxVer1 = BigDecimal.ZERO;
		if (maxVer2 == null)
			maxVer2 = BigDecimal.ZERO;

		// Take highest version from both
		BigDecimal currentMax = maxVer1.max(maxVer2);

		// Generate new version
		BigDecimal newVersion = currentMax.add(BigDecimal.ONE);

		Date now = new Date();

		// ====================================================
		// 3️⃣ CREATE RESUB SUMMARY RECORDS
		// ====================================================

		M_CA5_RESUB_Summary_Entity1 resubSummary1 = new M_CA5_RESUB_Summary_Entity1();
		M_CA5_RESUB_Summary_Entity2 resubSummary2 = new M_CA5_RESUB_Summary_Entity2();

		BeanUtils.copyProperties(updatedEntity1, resubSummary1);
		BeanUtils.copyProperties(updatedEntity2, resubSummary2);

		resubSummary1.setReportDate(reportDate1);
		resubSummary1.setReportVersion(newVersion);
		resubSummary1.setReportResubDate(now);

		resubSummary2.setReportDate(reportDate2);
		resubSummary2.setReportVersion(newVersion);
		resubSummary2.setReportResubDate(now);

		// ====================================================
		// 4️⃣ CREATE RESUB DETAIL RECORDS
		// ====================================================

		M_CA5_RESUB_Detail_Entity1 resubDetail1 = new M_CA5_RESUB_Detail_Entity1();
		M_CA5_RESUB_Detail_Entity2 resubDetail2 = new M_CA5_RESUB_Detail_Entity2();

		BeanUtils.copyProperties(updatedEntity1, resubDetail1);
		BeanUtils.copyProperties(updatedEntity2, resubDetail2);

		resubDetail1.setReportDate(reportDate1);
		resubDetail1.setReportVersion(newVersion);
		resubDetail1.setReportResubDate(now);

		resubDetail2.setReportDate(reportDate2);
		resubDetail2.setReportVersion(newVersion);
		resubDetail2.setReportResubDate(now);

		// ====================================================
		// 5️⃣ CREATE ARCHIVAL SUMMARY RECORDS
		// ====================================================

		M_CA5_Archival_Summary_Entity1 archSummary1 = new M_CA5_Archival_Summary_Entity1();
		M_CA5_Archival_Summary_Entity2 archSummary2 = new M_CA5_Archival_Summary_Entity2();

		BeanUtils.copyProperties(updatedEntity1, archSummary1);
		BeanUtils.copyProperties(updatedEntity2, archSummary2);

		archSummary1.setReportDate(reportDate1);
		archSummary1.setReportVersion(newVersion);
		archSummary1.setReportResubDate(now);

		archSummary2.setReportDate(reportDate2);
		archSummary2.setReportVersion(newVersion);
		archSummary2.setReportResubDate(now);

		// ====================================================
		// 6️⃣ CREATE ARCHIVAL DETAIL RECORDS
		// ====================================================

		M_CA5_Archival_Detail_Entity1 archDetail1 = new M_CA5_Archival_Detail_Entity1();
		M_CA5_Archival_Detail_Entity2 archDetail2 = new M_CA5_Archival_Detail_Entity2();

		BeanUtils.copyProperties(updatedEntity1, archDetail1);
		BeanUtils.copyProperties(updatedEntity2, archDetail2);

		archDetail1.setReportDate(reportDate1);
		archDetail1.setReportVersion(newVersion);
		archDetail1.setReportResubDate(now);

		archDetail2.setReportDate(reportDate2);
		archDetail2.setReportVersion(newVersion);
		archDetail2.setReportResubDate(now);

		// ====================================================
		// 7️⃣ SAVE EVERYTHING
		// ====================================================

		saveEntity(TBL_RESUB_SUMMARY1, resubSummary1, "reportDate", "reportVersion");
		saveEntity(TBL_RESUB_SUMMARY2, resubSummary2, "reportDate", "reportVersion");

		saveEntity(TBL_RESUB_DETAIL1, resubDetail1, "reportDate", "reportVersion");
		saveEntity(TBL_RESUB_DETAIL2, resubDetail2, "reportDate", "reportVersion");

		saveEntity(TBL_ARCH_SUMMARY1, archSummary1, "reportDate", "reportVersion");
		saveEntity(TBL_ARCH_SUMMARY2, archSummary2, "reportDate", "reportVersion");

		saveEntity(TBL_ARCH_DETAIL1, archDetail1, "reportDate", "reportVersion");
		saveEntity(TBL_ARCH_DETAIL2, archDetail2, "reportDate", "reportVersion");
	}

	public void updateReport(M_CA5_Summary_Entity1 updatedSummary) {

	    System.out.println("Came to M_CA5 Service");
	    System.out.println("Report Date: " + updatedSummary.getReportDate());

	    // Fetch existing SUMMARY
	    M_CA5_Summary_Entity1 existingSummary = getOneByDate(TBL_SUMMARY1, updatedSummary.getReportDate(), M_CA5_Summary_Entity1.class)
	            .orElseThrow(() -> new RuntimeException(
	                    "Summary record not found for REPORT_DATE: "
	                            + updatedSummary.getReportDate()));

	    // Audit old copy
	    M_CA5_Summary_Entity1 oldcopy = new M_CA5_Summary_Entity1();
	    BeanUtils.copyProperties(existingSummary, oldcopy);

	    // Fetch existing DETAIL
	    M_CA5_Detail_Entity1 existingDetail = getOneByDate(TBL_DETAIL1, updatedSummary.getReportDate(), M_CA5_Detail_Entity1.class)
	            .orElseGet(() -> {
	                M_CA5_Detail_Entity1 d = new M_CA5_Detail_Entity1();
	                d.setReportDate(updatedSummary.getReportDate());
	                return d;
	            });

	    try {

	        for (int i = 14; i <= 100; i++) {

	            String prefix = "R" + i + "_";

	            String[] fields = {
	                    "line_no",
	                    "note_holders",
	                    "name_of_instrument_programe",
	                    "issuing_entity_if_issued_throughan_spv",
	                    "issuance_date",
	                    "contractual_maturity_date",
	                    "effective_maturity_date_if_date",
	                    "amount",
	                    "amount_derecognised_p000",
	                    "total_p000"
	            };

	            for (String field : fields) {

	                String getterName = "get" + prefix + field;
	                String setterName = "set" + prefix + field;

	                try {

	                    Method getter = M_CA5_Summary_Entity1.class.getMethod(getterName);

	                    Method summarySetter = M_CA5_Summary_Entity1.class
	                            .getMethod(setterName, getter.getReturnType());

	                    Method detailSetter = M_CA5_Detail_Entity1.class
	                            .getMethod(setterName, getter.getReturnType());

	                    Object newValue = getter.invoke(updatedSummary);

	                    summarySetter.invoke(existingSummary, newValue);
	                    detailSetter.invoke(existingDetail, newValue);

	                } catch (NoSuchMethodException e) {
	                    continue;
	                }
	            }
	        }

	    } catch (Exception e) {
	        throw new RuntimeException("Error while updating M_CA5 Report 1", e);
	    }

	    String changes = auditService.getChanges(oldcopy, existingSummary);

	    if (!changes.isEmpty()) {

	        saveEntity(TBL_SUMMARY1, existingSummary, "reportDate");
	        saveEntity(TBL_DETAIL1, existingDetail, "reportDate");

	        auditService.compareEntitiesmanual(
	                oldcopy,
	                existingSummary,
	                updatedSummary.getReportDate().toString(),
	                "M CA5 Summary Screen",
	                "M_CA5_SUMMARY_1");
	    }
	}
	
