	public List<Object[]> getM_CA5Resub() {
		List<Object[]> resubList = new ArrayList<>();
		try {
			List<M_CA5_Archival_Summary_Entity1> latestArchivalList = getAllWithVersion(TBL_ARCH_SUMMARY1, M_CA5_Archival_Summary_Entity1.class);

			if (latestArchivalList != null && !latestArchivalList.isEmpty()) {
				for (M_CA5_Archival_Summary_Entity1 entity : latestArchivalList) {
					resubList.add(new Object[] { entity.getReportDate(), entity.getReportVersion(),
							entity.getReportResubDate() });
				}
				System.out.println("Fetched " + resubList.size() + " record(s)");
			} else {
				System.out.println("No archival data found.");
			}

		} catch (Exception e) {
			System.err.println("Error fetching M_CA5 Resub data: " + e.getMessage());
			e.printStackTrace();
		}
		return resubList;
	}

