	public void updateReportReSub(M_CA5_Summary_Entity1 updatedEntity1, M_CA5_Summary_Entity2 updatedEntity2) {

		System.out.println("Came to M_CA5 Resub Service");
		System.out.println("Report Date: " + updatedEntity1.getReportDate());

		Date reportDate = updatedEntity1.getReportDate();
		BigDecimal newVersion = BigDecimal.ONE;

		try {
			// 🔹 Fetch the latest archival version for this report date from Entity1
			Optional<M_CA5_Archival_Summary_Entity1> latestArchivalOpt1 = getLatestByDate(TBL_ARCH_SUMMARY1, reportDate, M_CA5_Archival_Summary_Entity1.class);

			if (latestArchivalOpt1.isPresent()) {
				M_CA5_Archival_Summary_Entity1 latestArchival = latestArchivalOpt1.get();
				try {
					newVersion = latestArchival.getReportVersion().add(BigDecimal.ONE);
				} catch (NumberFormatException e) {
					System.err.println("Invalid version format. Defaulting to version 1");
					newVersion = BigDecimal.ONE;
				}
			} else {
				System.out.println("No previous archival found for date: " + reportDate);
			}

			// 🔹 Prevent duplicate version number in Repo1
			boolean exists = existsByDateAndVersion(TBL_ARCH_SUMMARY1, reportDate, newVersion);

			if (exists) {
				throw new RuntimeException("⚠ Version " + newVersion + " already exists for report date " + reportDate);
			}

			// Copy data from summary to archival entities for all 3 entities
			M_CA5_Archival_Summary_Entity1 archivalEntity1 = new M_CA5_Archival_Summary_Entity1();
			M_CA5_Archival_Summary_Entity2 archivalEntity2 = new M_CA5_Archival_Summary_Entity2();

			org.springframework.beans.BeanUtils.copyProperties(updatedEntity1, archivalEntity1);
			org.springframework.beans.BeanUtils.copyProperties(updatedEntity2, archivalEntity2);

			// Set common fields
			Date now = new Date();
			archivalEntity1.setReportDate(reportDate);
			archivalEntity2.setReportDate(reportDate);

			archivalEntity1.setReportVersion(newVersion);
			archivalEntity2.setReportVersion(newVersion);

			archivalEntity1.setReportResubDate(now);
			archivalEntity2.setReportResubDate(now);

			System.out.println("Saving new archival version: " + newVersion);

			// Save to all three archival repositories
			saveEntity(TBL_ARCH_SUMMARY1, archivalEntity1, "reportDate", "reportVersion");
			saveEntity(TBL_ARCH_SUMMARY2, archivalEntity2, "reportDate", "reportVersion");

			System.out.println("Saved archival version successfully: " + newVersion);

		} catch (Exception e) {
			e.printStackTrace();
			throw new RuntimeException("Error while creating M_CA5 archival resubmission record", e);
		}
	}

	// Normal Format Excel
	public byte[] getM_CA5Excel(String filename, String reportId, String fromdate, String todate, String currency,
			String dtltype, String type, String format, BigDecimal version) throws Exception {

		logger.info("Service: Starting Excel generation process in memory.");

		System.out.println("======= Download SCREEN =======");
		System.out.println("TYPE      : " + type);
		System.out.println("FORMAT    : " + format);
		System.out.println("DTLTYPE   : " + dtltype);
		System.out.println("DATE      : " + todate);
		System.out.println("VERSION   : " + version);
		System.out.println("===============================");

		logger.info("DownloadFile: reportId={}, filename={}, type={}, version={}", reportId, filename, type, version);

		// ✅ Parse date only once
		Date reportDate;
		try {
			reportDate = parseReportDate(todate);
		} catch (ParseException e) {
			logger.error("Invalid report date format: {}", todate, e);
			throw new RuntimeException("Date format must be dd-MMM-yyyy (e.g. 31-Jul-2025)");
		}

		// ================================
		// ✅ ARCHIVAL Routing
		// ================================
		if ("ARCHIVAL".equalsIgnoreCase(type) && version != null) {
			return getExcelM_CA5ARCHIVAL(filename, reportId, fromdate, todate, currency, dtltype, type, format,
					version);
		}

		// ================================
		// ✅ RESUB Routing
		// ================================
		if ("RESUB".equalsIgnoreCase(type) && version != null) {
			logger.info("Service: Generating RESUB report for version {}", version);
			return BRRS_M_CA5ResubExcel(filename, reportId, fromdate, todate, currency, dtltype, type, format, version);
		}

		// ================================
		// ✅ EMAIL Format Routing
		// ================================
		if ("email".equalsIgnoreCase(format) && version == null) {
			logger.info("Service: Generating Email report");
			return getEmail_M_CA5Excel(filename, reportId, fromdate, todate, currency, dtltype, type, version);
		}

		// ================================
		// ✅ NORMAL EXCEL GENERATION
		// ================================

		List<M_CA5_Summary_Entity1> dataList1 = getByDate(TBL_SUMMARY1, reportDate, M_CA5_Summary_Entity1.class);

		List<M_CA5_Summary_Entity2> dataList2 = getByDate(TBL_SUMMARY2, reportDate, M_CA5_Summary_Entity2.class);

		if (dataList1.isEmpty()) {
			logger.warn("Service: No data found for M_CA5 report for date {}", todate);
			return new byte[0];
		}

		String templateDir = env.getProperty("output.exportpathtemp");
		Path templatePath = Paths.get(templateDir, filename);

		logger.info("Service: Loading template from path: {}", templatePath.toAbsolutePath());

		if (!Files.exists(templatePath)) {
			throw new FileNotFoundException("Template file not found at: " + templatePath.toAbsolutePath());
		}

		if (!Files.isReadable(templatePath)) {
			throw new SecurityException("Template exists but is not readable: " + templatePath.toAbsolutePath());
		}

		// ================================
		// ✅ EXCEL PROCESSING
		// ================================
		try (InputStream templateInputStream = Files.newInputStream(templatePath);
				Workbook workbook = WorkbookFactory.create(templateInputStream);
				ByteArrayOutputStream out = new ByteArrayOutputStream()) {

			Sheet sheet = workbook.getSheetAt(0);
			CreationHelper createHelper = workbook.getCreationHelper();

			// -------- DATE STYLE --------
			CellStyle dateStyle = workbook.createCellStyle();
			dateStyle.setDataFormat(createHelper.createDataFormat().getFormat("dd-MM-yyyy"));
			dateStyle.setBorderBottom(BorderStyle.THIN);
			dateStyle.setBorderTop(BorderStyle.THIN);
			dateStyle.setBorderLeft(BorderStyle.THIN);
			dateStyle.setBorderRight(BorderStyle.THIN);

			// -------- TEXT STYLE --------
			CellStyle textStyle = workbook.createCellStyle();
			textStyle.setBorderBottom(BorderStyle.THIN);
			textStyle.setBorderTop(BorderStyle.THIN);
			textStyle.setBorderLeft(BorderStyle.THIN);
			textStyle.setBorderRight(BorderStyle.THIN);

			// -------- NUMBER STYLE --------
			Font font = workbook.createFont();
			font.setFontHeightInPoints((short) 8);
			font.setFontName("Arial");

			CellStyle numberStyle = workbook.createCellStyle();
			numberStyle.setBorderBottom(BorderStyle.THIN);
			numberStyle.setBorderTop(BorderStyle.THIN);
			numberStyle.setBorderLeft(BorderStyle.THIN);
			numberStyle.setBorderRight(BorderStyle.THIN);
			numberStyle.setFont(font);

			// ================================
			// ✅ Populate Data
			// ================================
			if (!dataList1.isEmpty()) {
				populateEntity1Data(sheet, dataList1.get(0), textStyle, numberStyle, dateStyle);
			}

			if (!dataList2.isEmpty()) {
				populateEntity2Data(sheet, dataList2.get(0), textStyle, numberStyle, dateStyle);
			}

			// Evaluate formulas
			workbook.getCreationHelper().createFormulaEvaluator().evaluateAll();

			workbook.write(out);

			logger.info("Service: Excel successfully generated ({} bytes).", out.size());
			ServletRequestAttributes attrs = (ServletRequestAttributes) RequestContextHolder.getRequestAttributes();
			if (attrs != null) {
				HttpServletRequest request = attrs.getRequest();
				String userid = (String) request.getSession().getAttribute("USERID");
				auditService.createBusinessAudit(userid, "DOWNLOAD", "M_CA5 SUMMARY", null, "BRRS_M_CA5_SUMMARYTABLE");
			}
			return out.toByteArray();
		}
	}

